#include "masked_cumsum_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

// UB budget: inX + inMask + outY = 3 tiles * 4 bytes each
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // 192KB
static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t HARD_CAP_ELEMS = 16384;  // per tile size limit
static constexpr uint32_t MAX_BLOCKS = 24;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    MaskedCumsumCustomTilingData tiling;

    auto shape = context->GetInputShape(0)->GetOriginShape();
    const uint32_t totalLength = shape.GetShapeSize();
    const uint32_t dims = shape.GetDimNum();
    // Assume dim=1 (last dim) and at least 2D. Compute rowLen as last dimension size.
    uint32_t rowLen = shape.GetDim(dims - 1);
    uint32_t totalRows = (dims == 1) ? 1 : (totalLength / rowLen);

    // Compute tile length from UB budget: 3 float buffers (x, mask, y)
    uint32_t maxTile = UB_BUDGET_BYTES / (3 * sizeof(float));
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    uint32_t tileLen = (rowLen < maxTile) ? AlignDown(rowLen, ALIGN_ELEMS) : maxTile;
    if (tileLen < ALIGN_ELEMS) tileLen = ALIGN_ELEMS; // but may be > rowLen, correct later
    if (tileLen > rowLen) tileLen = rowLen;

    // Set blockDim: one block per group of rows, up to MAX_BLOCKS
    uint32_t blockDim = (totalRows < MAX_BLOCKS) ? totalRows : MAX_BLOCKS;
    if (blockDim < 1) blockDim = 1;
    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_rowLen(rowLen);
    tiling.set_tileLen(tileLen);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

