kernel_src="""

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelMaskedCumsumCustom {
public:
    __aicore__ inline KernelMaskedCumsumCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR mask, GM_ADDR y,
                                uint32_t totalLength, uint32_t rowLen,
                                uint32_t tileLen, uint32_t blockDim) {
        totalLen_ = totalLength;
        rowLen_ = rowLen;
        tileLen_ = tileLen;
        blockDim_ = blockDim;
        numRows_ = (rowLen_ > 0) ? (totalLen_ / rowLen_) : 0;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        maskGm_.SetGlobalBuffer((__gm__ float*)mask, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(inQueueMask_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process() {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        // Partition rows across blocks
        uint32_t rowsPerBlock = (numRows_ + blockDim_ - 1) / blockDim_;
        uint32_t startRow = blockIdx * rowsPerBlock;
        uint32_t endRow = startRow + rowsPerBlock;
        if (startRow >= numRows_) return;
        if (endRow > numRows_) endRow = numRows_;

        for (uint32_t row = startRow; row < endRow; ++row) {
            uint32_t rowOffset = row * rowLen_;
            // Process row in tiles of tileLen_ along the row
            uint32_t processed = 0;
            float carrySum = 0.0f;
            while (processed < rowLen_) {
                uint32_t curLen = rowLen_ - processed;
                if (curLen > tileLen_) curLen = tileLen_;
                // Prefetch next tile (if any) for overlap; simple version:
                CopyIn(rowOffset + processed, curLen);
                Compute(curLen, carrySum);
                CopyOut(rowOffset + processed, curLen);
                processed += curLen;
            }
        }
    }

private:
    __aicore__ inline void CopyIn(uint32_t offset, uint32_t len) {
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[offset], len);
        inQueueX_.EnQue(xLocal);

        AscendC::LocalTensor<float> maskLocal = inQueueMask_.AllocTensor<float>();
        AscendC::DataCopy(maskLocal, maskGm_[offset], len);
        inQueueMask_.EnQue(maskLocal);
    }

    __aicore__ inline void Compute(uint32_t len, float& carry) {
        AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<float> maskLocal = inQueueMask_.DeQue<float>();
        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();

        // Elementwise product: t = x * mask
        // Then inclusive scan: y[i] = t[i] + (i>0 ? y[i-1] : 0)
        float sum = carry;
        for (uint32_t i = 0; i < len; ++i) {
            float val = xLocal(i) * maskLocal(i);
            sum += val;
            yLocal(i) = sum;
        }
        carry = sum; // pass to next tile

        outQueueY_.EnQue(yLocal);
        inQueueX_.FreeTensor(xLocal);
        inQueueMask_.FreeTensor(maskLocal);
    }

    __aicore__ inline void CopyOut(uint32_t offset, uint32_t len) {
        AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        AscendC::DataCopy(yGm_[offset], yLocal, len);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueMask_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> maskGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t rowLen_ {0};
    uint32_t tileLen_ {0};
    uint32_t blockDim_ {0};
    uint32_t numRows_ {0};
};

extern "C" __global__ __aicore__ void masked_cumsum_custom(GM_ADDR x, GM_ADDR mask, GM_ADDR y,
                                                           GM_ADDR workspace, GM_ADDR tiling) {
    GET_TILING_DATA(tiling_data, tiling);
    KernelMaskedCumsumCustom op;
    op.Init(x, mask, y,
            tiling_data.totalLength,
            tiling_data.rowLen,
            tiling_data.tileLen,
            tiling_data.blockDim);
    op.Process();
}
